import{_ as t,o as n,c as r,ag as o}from"./chunks/framework.DXGyWiRo.js";const i="/images/uebung083.jpg",a="/images/uebung085.jpg",s="/images/uebung076.jpg",p="/images/uebung084.jpg",l="/images/uebung077.jpg",q=JSON.parse('{"title":"Übung Lektion 48","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/uebung48.md","filePath":"lektionen/uebung48.md"}'),u={name:"lektionen/uebung48.md"};function c(h,e,b,m,k,d){return n(),r("div",null,[...e[0]||(e[0]=[o('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="ubung-lektion-48" tabindex="-1">Übung Lektion 48 <a class="header-anchor" href="#ubung-lektion-48" aria-label="Permalink to &quot;Übung Lektion 48&quot;">​</a></h1><p>A) Übersetzen Sie die सुभाषितानि zu Beginn der Lektion.</p><p>सत्यम् वद ॥१॥</p><blockquote><p>Sprich die Wahrheit!</p></blockquote><p>धर्मं चर ॥२॥</p><blockquote><p>Halte dich an Recht und Sitte!</p></blockquote><p>मातृदेवो भव ॥३॥</p><blockquote><p>Halte Deine Mutter wie eine Göttin!</p></blockquote><p>गौरवं प्राप्यते दानात् ॥४॥</p><blockquote><p>Freigebigkeit verleiht Würde.</p></blockquote><p>श्वः कार्यमद्य कुर्वीत ॥५॥</p><blockquote><p>Tu heute, was morgen zu tun ist!<br> Verschiebe nicht auf morgen, was du heute kannst besorgen!</p></blockquote><p>विद्याविहीनः पशुः ॥६॥</p><blockquote><p>Vieh ist ohne Wissen.</p></blockquote><p>लाघवं वैयाकरणस्य भूषणम् ॥७॥</p><blockquote><p>Kürze ist der Schmuck des Grammatikers.</p></blockquote><p><img src="'+i+'" alt=""><br> Abb.: विद्याविहीनः पशुः<br> ca. 1900<br> [Bildquelle: whatsthatpicture. -- <a href="http://www.flickr.com/photos/whatsthatpicture/3011403804/in/set-72157608574746511/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/whatsthatpicture/3011403804/in/set-72157608574746511/</a>  -- Zugriff am 2009-01-24. -- <a href="http://creativecommons.org/licenses/by-nc/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung, keine kommerzielle Nutzung)]</p><p>B) Übersetzen Sie ins Sanskrit (verwenden Sie dabei den Imperativ und möglichst Wurzeln der 2. und 3. Präsensklasse):</p><p>1. Nachdem du einen Sohn bekommen hast, verlasse die Familie!</p><blockquote><p>पुत्रं लब्ध्वा कुलं जहाहि । जहीहि । जहिहि ॥१॥</p></blockquote><p>2. Nachkommen des Puru, fürchtet euch vor denen, die Böses getan haben!</p><blockquote><p>पैरवाः कृतपापेभ्यो बिभीत ॥२॥</p></blockquote><p>3. Die Mädchen sollen den Bettlern Speise geben.</p><blockquote><p>कन्या भिक्षुभ्यो ऽन्नं ददतु ॥३॥</p></blockquote><p>4. Wir wollen sprechen.</p><blockquote><p>ब्रवाम । वचाम ॥४॥</p></blockquote><p><img src="'+a+'" alt=""><br> Abb.: वचाम<br> &quot;Musicians Preachers&quot;, ca. 1900<br> [Bildquelle: whatsthatpicture. -- <a href="http://www.flickr.com/photos/whatsthatpicture/2995927204/in/set-72157608574746511/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/whatsthatpicture/2995927204/in/set-72157608574746511/</a>. -- Zugriff am 2009-01-24. -- <a href="http://creativecommons.org/licenses/by-nc/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung, keine kommerzielle Nutzung)]</p><p>5. Mit den Worten &quot;Komm Mönch!&quot; nahm Buddha den Mann in den Mönchsorden auf (उपसम्पद् Kausativ).</p><blockquote><p>एहि भिक्ष इति बुद्धो नरमुपसमपादयत् ॥५॥</p></blockquote><p>6. Seid wahre Nachfahren Manus!</p><blockquote><p>सद्मानवाः स्त । सन्मानवाः स्त ॥६॥</p></blockquote><p>7. Ich will शिव und die anderen Götter preisen.</p><blockquote><p>शिवादिदेवान्स्तवानि ॥७॥</p></blockquote><p>8. Erzähle!</p><blockquote><p>आख्याहि ॥८॥</p></blockquote><p>9. Miss die Höllen aus!</p><blockquote><p>नरकान्मिमीष्व ॥९॥</p></blockquote><p>10. Sie (pl.) sollen auf diesen Liegen liegen.</p><blockquote><p>एतेषु शयनेषु शेरताम् ॥१०॥</p></blockquote><p>11. Die tigergleichen Männer sollen die töten, die Indra feind sind.</p><blockquote><p>पुरुषव्याघ्रा इन्द्रशत्रून्घ्नन्तु ॥११॥</p></blockquote><p>12. Konzentriere dich!</p><blockquote><p>समाधेहि । समाधत्स्व ॥१२॥</p></blockquote><p>13. Sitzt hier!</p><blockquote><p>अत्राध्वम् ॥१२॥</p></blockquote><p>14. Wir wollen diese Früchte essen.</p><blockquote><p>तानि फलान्यदाम ॥१४॥</p></blockquote><p>15. Der Diener soll die Kuh melken.</p><blockquote><p>दासो धेनुं दोग्धु ॥१५॥</p></blockquote><p>16. König, hüte den Dharma und die Leute!</p><blockquote><p>राजन्धर्मं जनांश्च पाहि ॥१६॥</p></blockquote><p>17. Lehre die Schüler den Veda!</p><blockquote><p>शिष्याञ्शाधि वेदम् । शिष्याञ्छाधि वेदम् ॥१७॥</p></blockquote><p>18. Er soll neue Kleider anziehen.</p><blockquote><p>नवानि वस्त्राणि वस्ताम् ॥१८॥</p></blockquote><p>19. Sie (pl.) sollen in meinem Haus sitzen.</p><blockquote><p>मम गृह आसताम् ॥१९॥</p></blockquote><p>20. Ehemänner sollen ihre Gattinnen erhalten (i. S. v. Unterhalt).</p><blockquote><p>भर्तारो भार्या बिभ्रतु ॥२०॥</p></blockquote><p><img src="'+s+'" alt=""><br> Abb.: तानि फलान्यदाम<br> āmalaka = Ambla = <em>Phyllanthus emblica</em> L.<br> [Bildquelle: Harshad Sharma. -- <a href="http://www.flickr.com/photos/harshadsharma/66105376/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/harshadsharma/66105376/</a>. -- Zugriff am 2009-01-23. -- <a href="http://creativecommons.org/licenses/by-nc-nd/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung, keine kommerzielle Nutzung, keine Bearbeitung)]</p><p><img src="'+p+'" alt=""><br> Abb.: अस्वतन्त्राः स्त्रियः कार्याः पुरुषैः स्वैर्दिवानिशम् ।<br> &quot;Hindu woman&quot;, ca. 1900<br> [Bildquelle: whatsthatpicture. -- <a href="http://www.flickr.com/photos/whatsthatpicture/2993550296/in/set-72157608574746511/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/whatsthatpicture/2993550296/in/set-72157608574746511/</a>. -- Zugriff am 2009-01-24. -- <a href="http://creativecommons.org/licenses/by-nc/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung, keine kommerzielle Nutzung)]</p><p>मनुस्मृति ९ (स्त्रीधर्मः):</p><p>अस्वतन्त्राः स्त्रियः कार्याः पुरुषैः स्वैर्दिवानिशम् ।<br> विषयेषु च सज्जन्त्यः संस्थाप्या आत्मनो वशे ॥२॥</p><blockquote><p>Die Männer müssen ihre Frauen Tag und Nacht abhängig machen. Die Frauen, die an Sinnesobjekten haften, müssen unter die Kontrolle ihrer Männer gebracht werden.</p></blockquote><p>पिता र्क्षति कौमरे भर्ता रक्षति यौवने ।<br> रक्षन्ति स्थाविरे पुत्रा न स्त्री स्वातन्त्र्यमर्हति ॥३॥</p><blockquote><p>Ihr Vater behütet sie zur Zeit ihrer Jungfernschaft, ihr Gatte behütet sie in ihrer Jugend, ihre Söhne behüten sie im Alter. Nicht ist eine Frau fähig zur Eigenständigkeit.</p></blockquote><p>काले ऽदाता पिता वाच्यो वाच्यश्चानुपनयन्पतिः ।<br> मृते भर्तरि पुत्रस्तु वाच्यो मातुररक्षिता ॥४॥</p><blockquote><p>Tadelnswert ist der Vater, der seine Tochter nicht zur rechten Zeit zur Hochzeit verspricht. Tadelnswert ist auch der Gatte, der nicht zur rechten Zeit mit ihr Geschlechtsverkehr hat. Der Sohn ist aber zu tadeln, der nach dem Tod ihres Gatten kein Behüter seiner Mutter ist.</p></blockquote><p>सूक्ष्मेभ्यो ऽपि प्रसङ्गेभ्यः स्त्रियो रक्ष्या विशेषतः ।<br> द्वयोर्हि कुलयोः शोकमावहेयुररक्षिताः ॥५॥</p><blockquote><p>Besonders behüten muss man Frauen vor auch geringfügigen Gelegenheiten. Unbehütet würden sie Kummer in zwei Familien bringen.</p></blockquote><p>इमं हि सर्ववर्णानां पश्यन्तो धर्ममुत्तमम् ।<br> यतन्ते रक्षितुं भार्यां भर्तारो दुर्बला अपि ॥६॥</p><blockquote><p>Dies als höchste Aufgabe aller Stände sehend, bemühen sich auch schwache Gatten, ihre Gattinnen zu behüten.</p></blockquote><p>स्वां प्रसूतिं चरित्रं च कुलमात्मानमेव च ।<br> स्वं च धर्मं प्रयत्नेन जायां रक्षन्हि रक्षति ॥७॥</p><blockquote><p>Wer seine Frau sorgsam behütet, behütet nämlich seine Nachkommenschaft, seinen Lebenswandel, seine Familie, sich selbst und seine religiöse Pflicht.</p></blockquote><p>पतिर्भार्यां संप्रविश्य गर्भो भूत्वेह जायते ।<br> जायायास्तद्धि जायात्वं यद् अस्यां जायते पुनः ॥८॥</p><blockquote><p>Der Gatte tritt in seine Gattin ein, wird zum Embryo und wird dann auf dieser Welt geboren. Es ist das Frausein der Frau (jâyâ), dass ihr Mann von ihr wiedergeboren wird.</p></blockquote><p>Zur Erklärung dieses Textes siehe:</p><p><img src="'+l+'" alt=""><br> Abb.: पतिर्भार्यां संप्रविश्य गर्भो भूत्वेह जायते<br> [Bildquelle: Henna Sooq. -- <a href="http://www.flickr.com/photos/hennasooq/458793530/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/hennasooq/458793530/</a>. -- Zugriff am 2009-01-23. -- <a href="http://creativecommons.org/licenses/by-nc-nd/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung, keine kommerzielle Nutzung, keine Bearbeitung)]</p>',79)])])}const f=t(u,[["render",c]]);export{q as __pageData,f as default};
